INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027ceee3c98b0941765ac0', '酒店地理位置不错，离北京路挺近的，早餐非常好吃，连吃两天，非常的满意，下次来广州还会继续打卡，花园酒店的花园确实像花园一般，景美鱼肥！', '["https://dimg04.c-ctrip.com/images/0231312000d3w2j72A1D0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000d3w2i5h2907_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233e12000d3w4k8lBFCB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-02', '花园双床房', '双床房', '家庭亲子', 67, 0, 17, 7, '["周边配套","餐饮设施","整体满意度"]'::jsonb, '周边配套', '餐饮设施', '整体满意度'),
('68027ceee3c98b0941765ac1', '广州老牌酒店，环境很不错，有瀑布花园。服务很好要给赞。早餐很丰富。出门就是地铁站。唯一不足就是酒店房间有点陈旧。', '["https://dimg04.c-ctrip.com/images/0230412000d9466fo9DCE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000d94gs7a24C6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231c12000d94in1oF718_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-02-20', '花园双床房', '双床房', '家庭亲子', 56, 0, 6, 7, '["交通便利性","餐饮设施","整体满意度"]'::jsonb, '交通便利性', '餐饮设施', '整体满意度'),
('68027ceee3c98b0941765ac2', '比预期的好很多，老牌的酒店，原以为设施会老旧，但房间维护的很好，很干净，很温馨，很有岭南特色。地下停车场有3层，充分满足了停车需求，就是停车场的电梯跟酒店是分开的，要绕过一节路，室外的，刚好下点小雨，自己拖着行李箱带着几个小朋友有点不方便。办入住的时候等的时间有点久，可能人太多的缘故，大堂真的是人来人往，古色古香的感觉，吃饭的、参观的、拍照的、络绎不绝……办入住的时候房间没打扫好，去3楼桃园馆吃了顿饭，正宗的粤菜，摆盘正、味道正，除了价格贵没别的缺点了，推荐大家可以尝试一下。酒店后花园很漂亮，有水池和鲤鱼，还有瀑布，景色怡人，另外还享受了30层的行政酒廊，服务员Ken和Zocy非常热情有礼貌，会主动询问和帮忙，非常感谢他们高水准的服务，总之，花园酒店可以让你更直观的了解广州的一些地方特色和风土人情，值得一住。', '["https://dimg04.c-ctrip.com/images/0231312000d2gdevyF7CD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232c12000d2gd0mfA96A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000d2fn5r689A2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000d2fuqpt4FF9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233r12000d2g6fsa74FB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230m12000d2g23q9E9D0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231i12000d2g23qbCF9B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234612000d2g4dy68129_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000d2g2tsbAEAD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-29', '粤韵大床套房', '套房', '家庭亲子', 359, 0, 41, 9, '["整体满意度","房间设施","公共设施"]'::jsonb, '整体满意度', '房间设施', '公共设施'),
('68027ceee3c98b0941765ac3', '大堂很豪华漂亮，也有过年的氛围，房间稍微小了点。总之很好的住宿体验。到处都很漂亮，而且很有年味，感觉像在自己家过年一样。', '["https://dimg04.c-ctrip.com/images/0231812000d6gsuwuF313_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231p12000d6gt3wy00F5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236112000d6gtd8z57C7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-11', '城央绿意双床房', '双床房', '家庭亲子', 60, 0, 15, 5, '["整体满意度","公共设施"]'::jsonb, '整体满意度', '公共设施', NULL),
('68027ceee3c98b0941765ac4', '好好好好好好好好好好好好好好好好好好好好好好好好
设施：好好好好好好好好好好好好好
卫生：好好好好好好好好好好
环境：好好好好好好好好好好好好好', '["https://dimg04.c-ctrip.com/images/0232k224x8tu48mysDDD4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p224x8tu4ayh4234F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235b224x8tu4ayh5E22E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y224x8tu3wmc113E6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-22', '花园大床房', '大床房', '情侣出游', 72, 0, 14, 1, '["整体满意度","卫生状况"]'::jsonb, '整体满意度', '卫生状况', NULL),
('68027ceee3c98b0941765ac5', '老城区的老牌酒店，去哪里都很方便。过年期间有很多活动，工作服务人员也很多。美中不足的是早餐一般，品种很少，亲子设施少。', '["https://dimg04.c-ctrip.com/images/0234212000d6orjs24828_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u12000d6p9ajx207D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234b12000d6p3dbaF9DB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-12', '花园大床房', '大床房', '家庭亲子', 59, 0, 11, 6, '["交通便利性","周边配套","餐饮设施"]'::jsonb, '交通便利性', '周边配套', '餐饮设施'),
('68027cf8e3c98b0941765ac6', '续住豪华白金五星花园酒店，环境优美，房间舒适，凌璇阁旋转餐厅非常棒！早餐品种丰盛，360゜全景欣赏广州风景。', '["https://dimg04.c-ctrip.com/images/0237112000d8xo2z3A6C8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000d8xxw43AC7C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000d8xylimA27E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-20', '花园双床房', '双床房', '朋友出游', 54, 0, 103, 8, '["餐饮设施","整体满意度","景观/朝向"]'::jsonb, '餐饮设施', '整体满意度', '景观/朝向'),
('68027cf8e3c98b0941765ac7', '花园酒店具有广州特色，尤其大堂非常富丽堂皇，还有花园瀑布小桥流水。酒店周边热闹，地铁淘金站就在旁边，购物方便。酒店二楼的中餐厅早茶好吃。毕竟是1985年开业的酒店，房间内部如果重新装修就更好了。', '["https://dimg04.c-ctrip.com/images/0236h12000cn85oznFE03_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000cn8b7odCF03_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234o12000cn89e51D30F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232j12000cn88tmc12AC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235812000cn84e570FDA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235012000cn87w60519D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236d12000cn8aerc7C05_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233k12000cn86tzqD3E6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000cn8ctpa07AF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-11-27', '红棉双床套房', '套房', '家庭亲子', 97, 0, 80, 8, '["周边配套","交通便利性","餐饮设施"]'::jsonb, '周边配套', '交通便利性', '餐饮设施'),
('68027cf8e3c98b0941765ac8', '老牌五星酒店，服务、餐饮、卫生、环境都很赞，距离5号线淘金站，几乎零距离，特别适合家庭出游选择，会推荐给朋友。', '["https://dimg04.c-ctrip.com/images/0236t12000d8sb8h42693_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233r12000d8seu0j1534_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000d8sfece6243_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-19', '粤韵双床套房', '套房', '家庭亲子', 55, 0, 6, 7, '["整体满意度","交通便利性","餐饮设施"]'::jsonb, '整体满意度', '交通便利性', '餐饮设施'),
('68027cf8e3c98b0941765ac9', '交通便利，就在地铁口。前台服务周到，房间有缺什么也是第一时间送到，5星服务很到位。还有自己的博物馆和后花园，入住体验感很好，下次还来，推荐', '["https://dimg04.c-ctrip.com/images/0232p12000db9x3tr8274_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235k12000db9pz7k818C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235u12000db9ysha4010_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-29', '粤韵双床套房', '套房', '家庭亲子', 69, 0, 1, 8, '["交通便利性","前台服务","整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度'),
('68027cf8e3c98b0941765aca', '酒店环境很美，前台给升级了套房，房间很大也很干净，很满意，春节氛围感很足，一直到初五都有年俗活动，服务态度很好。', '["https://dimg04.c-ctrip.com/images/0231q12000d7xgxuq1EE5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-16', '花园大床房', '大床房', '家庭亲子', 56, 0, 17, 8, '["整体满意度","前台服务","卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况'),
('68027cf8e3c98b0941765acb', '酒店连住三晚，满意酒店位置，地铁公交打车都方便。酒店还有瀑布花园，博物馆，非常有特色。除了附近有工地，半夜时有噪音，其他都赞。', '["https://dimg04.c-ctrip.com/images/0231512000d40kdimC1F7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-02', '花园双床房', '双床房', '家庭亲子', 63, 0, 17, 8, '["交通便利性","周边配套","安静程度"]'::jsonb, '交通便利性', '周边配套', '安静程度'),
('68027cf8e3c98b0941765acc', '第一次入住花园酒店，高大上的感觉，特别四楼的【博物馆】相当的不错，赞????????！瀑布餐厅的自助晚餐品种丰富，三文鱼柳，厚切的口感很过瘾！其他食材也不错，开启增肥的节奏！最感动的是，餐厅知道我生日，由经理携同祝贺团队一边唱着生日歌，一边送来了生日蛋糕和一支玫瑰花，暖暖的！可惜，客服后续服务跟不上！我在订房时已经明确需要加床，办理入住时再次重申要马上加床，一路颠簸很累！结果等了一个多小时，电话催了几次，才过来装上。感觉五星酒店不应该是这样的！', '["https://dimg04.c-ctrip.com/images/0232k12000cpn8brr74F4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232a12000cpn8ayu9624_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000cpn84egB670_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000cpn84eu3121_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235812000cpn93k3A5F2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m12000cpn94qpDDF0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-12-10', '羊羊得意主题大床房', '主题房', '家庭亲子', 224, 0, 10, 8, '["餐饮设施","客房服务","整体满意度"]'::jsonb, '餐饮设施', '客房服务', '整体满意度'),
('68027cf8e3c98b0941765acd', '完全出乎意料的好！无论是设施服务还是饮食酒店文化都做的非常棒，新年入住气氛也很浓郁，体验很好，会再来。非常适合带孩子。', '["https://dimg04.c-ctrip.com/images/0235512000d7l6aaf7B0F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000d7l8ce0D436_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000d7l2r763D93_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-15', '红棉大床套房', '套房', '家庭亲子', 59, 0, 8, 6, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('68027cf8e3c98b0941765ace', '来广州首选花园酒店，入住时告诉接待员我们已是第三次入住，那位帅哥Kasas非常专业和热情：“欢迎回家”，贴心地为我们升级了房间，赠送早餐和下午茶，太开心了，谢谢他。酒店的博物馆和老家俱展示都非常有特色，房间布置很漂亮，床品床单很高级的提花面料很舒服，也找服务员要了决明子枕头；打扫非常干净整洁；很慷慨的赠送饮用水；在酒店吃了荔湾亭和日料餐厅非常不错。', '["https://dimg04.c-ctrip.com/images/0232912000hmibx023195_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000hmi1sjsC2B1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233j12000hmidujy1316_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232a12000hmhscvy5759_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000hmhimcg8BBB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232612000hmhbvew7C70_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-06', '城央绿意大床房', '大床房', '其他', 175, 0, 5, 9, '["前台服务","整体满意度","客房服务"]'::jsonb, '前台服务', '整体满意度', '客房服务'),
('68027cf8e3c98b0941765acf', '不愧是白金五星酒店，出入方便，在越秀区中心位置，环境优美，是酒店花园，家人都觉得满意，下次还会考虑入住哦。', '["https://dimg04.c-ctrip.com/images/0233l12000d8hgl6z2E0B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235d12000d8hgu4492B8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236c12000d8hbdzz4D84_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233q12000d8h6n3y5AD1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000d8hfcxx4F52_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f12000d8h4nag394D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000d8hb52i1408_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000d8hbk52C85E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000d8hg42c8DEF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-18', '红棉双床套房', '套房', '家庭亲子', 53, 0, 27, 6, '["整体满意度","交通便利性","周边配套"]'::jsonb, '整体满意度', '交通便利性', '周边配套'),
('68027d03e3c98b0941765ad0', '老牌五星酒店 房间小 卫生不错  行政餐厅早餐热菜不算太多  晚餐基本凉菜 随便喝喝酒可以 味道一般 西点重磅蛋糕不错 可颂不太行 餐品要加强
  
服务生笑容可掬 有求必应 酒店4楼博物馆加分 很有情怀 亲切

家里老人比较喜欢 洗漱设施陈旧 房门木质变色 太破旧 需要翻新了。
 地理位置优越 淘金站去哪都方便
下次来广州 还会选择升级房间 看看如何', '["https://dimg04.c-ctrip.com/images/0233v12000cq1f6k81EE6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000cq1h15jD4EB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233812000cq1jwng7F32_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232612000cq1k7nb477D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-12-12', '花园双床房', '双床房', '其他', 177, 0, 34, 8, '["房间设施","餐饮设施","交通便利性"]'::jsonb, '房间设施', '餐饮设施', '交通便利性'),
('68027d03e3c98b0941765ad1', '服务非常热情，楼层都有管家，微笑服务。房间打扫及时，干净，有欢迎水果送想得很周到。桃园餐厅的菜品不错，没有低消。酒店出行很方便门口就是地铁。', '["https://dimg04.c-ctrip.com/images/0233612000d258rbdE31B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000d258qd27027_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000d258rxqDB80_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232f12000d258ryh35AF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-27', '红棉双床套房', '套房', '家庭亲子', 70, 0, 7, 7, '["前台服务","客房服务","交通便利性"]'::jsonb, '前台服务', '客房服务', '交通便利性'),
('68027d03e3c98b0941765ad2', '每间夜含2位行政礼遇（含下午茶及欢乐时光）：非常满意！服务很贴心，因为是一个人入住所以都是邀请朋友来happy hour，有一天多了一个朋友过来坐也能理解。下午茶点心很精致，只是晚了就会没有太多选择。
早餐: 早餐西餐种类较多，中餐选择相对较少，希望可以多一些本地早茶点心。', '["https://dimg04.c-ctrip.com/images/0231v324x8tlm7dwqBD8E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y324x8tlg9l7y7998_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-22', '花园大床房', '大床房', '独自旅行', 137, 0, 1, 8, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('68027d03e3c98b0941765ad3', '酒店服务、环境真的很棒，感谢行政走廊Tina、Echo、Kitty的优质服务，感谢客房整理员陶美芳的细心服务。只要客房设施陈旧了些，期待早日修缮，期待下次再来住??', '["https://dimg04.c-ctrip.com/images/0232i12000fbdo6vgCC6B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000fbdymp5F869_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232212000fbdnw81EB21_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230512000fbdxyp70692_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233112000fbdu60e3ED3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-08-30', '花园双床房', '双床房', '家庭亲子', 82, 0, 2, 7, '["前台服务","客房服务","房间设施"]'::jsonb, '前台服务', '客房服务', '房间设施'),
('68027d03e3c98b0941765ad4', '入住办理太费劲，人员效率慢，服务态度比较一般，对不起花园酒店这个名字，希望有待改善，毕竟花园酒店是广州人的美好记忆。', '["https://dimg04.c-ctrip.com/images/0231k12000d60sluvE081_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234t12000d60f51qB6A6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230z12000d60mhrrEE7B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-02-09', '红棉大床套房', '套房', '家庭亲子', 58, 0, 24, 6, '["前台服务","退房/入住效率"]'::jsonb, '前台服务', '退房/入住效率', NULL),
('68027d03e3c98b0941765ad5', '位置好、规模大，是一家非常有文化底蕴的酒店，但设施设备很有年代感了，服务还是不错的  春节期间大厅集市很有特色。', '["https://dimg04.c-ctrip.com/images/0231712000d6v8xht7366_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000d6v7lhx6AB4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000d6uihbeB31D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236q12000d6v4wx14788_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000d6ufjk6C43A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-02-13', '花园双床房', '双床房', '家庭亲子', 56, 0, 19, 6, '["整体满意度","周边配套","房间设施"]'::jsonb, '整体满意度', '周边配套', '房间设施'),
('68027d03e3c98b0941765ad6', '房间挺好的，环境不错，服务也好，酒店大气，有花园，花园里有许多锦鲤鱼，还有人造瀑布，循环水溪，花园溜达也很惬意。不愧为花园酒店。值得推荐。', '["https://dimg04.c-ctrip.com/images/0231112000dncp6dhE422_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233b12000dncoz8g9882_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236v12000dncoz8o2ADB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235r12000dncp0e15574_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y12000dncpal878CF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-11', '花园双床房', '双床房', '其他', 69, 0, 1, 8, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('68027d03e3c98b0941765ad7', '难得住宿我会写评论
感谢携程铂金会员 让我升级了房间
行政酒廊的服务真心不错
房间也很干净
服务员也很热情
最爱酒店花园里的鱼
小朋友玩了都不想离开', '["https://dimg04.c-ctrip.com/images/0232j12000cy88vke00CC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235812000cy89stlAF9F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230112000cy8fkdkAF4D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-16', '花园双床房', '双床房', '家庭亲子', 74, 0, 5, 6, '["整体满意度","客房服务","卫生状况"]'::jsonb, '整体满意度', '客房服务', '卫生状况'),
('68027d03e3c98b0941765ad8', '酒店很美，瀑布餐厅可以看锦鲤小朋友超喜欢，酒店服务也很好，给前台betty点个赞??态度耐心，看我们两个小朋友给不了连在一起的房间，还给我们升了房。住的很舒心，早餐也好吃。房间打扫的超干净。唯一不足就是可能外国人多，酒店房间太冷了，空调调高也没用，后面把空调关了挺好。总体说非常非常值得一住。', '["https://dimg04.c-ctrip.com/images/0231012000go853zn150D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b12000go85f6w4C39_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235t12000go7onr41E4C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000go7yvxr0AF5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-14', '花园大床房', '大床房', '家庭亲子', 146, 0, 3, 9, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68027d03e3c98b0941765ad9', '不愧是老牌的白金级五星级酒店，从下车到达开始见到的每一个服务人员都非常热情，特别是行政酒廊的 Carrie 和 Jaismine 为我们的下午茶和欢乐时光都提供了细致周到的服务，给全家包括老人和小孩都留下了难忘的回忆，谢谢。', '["https://dimg04.c-ctrip.com/images/0232p12000d3b8ksi7986_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000d3bawq8F675_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235u12000d3bbsic4A48_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230j12000d3bbsig24C5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232e12000d3bbjgo3670_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235r12000d3bbmrb5F00_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-31', '花园双床房', '双床房', '家庭亲子', 112, 0, 3, 9, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027d10e3c98b0941765ada', '酒店位置方便，硬件条件好，前台免费升级房型，非常感谢！下次来广州还会选择入住', '["https://dimg04.c-ctrip.com/images/0236u12000dfhj7gi8626_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-16', '花园大床房', '大床房', '商务出差', 38, 0, 30, 6, '["整体满意度","交通便利性","前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务'),
('68027d10e3c98b0941765adb', '房间干净卫生整齐，大堂富丽堂皇，像一座艺术殿堂，服务态度好。瀑布餐厅漂亮值得打卡，四楼博物馆讲述了中国酒店发展史。', '["https://dimg04.c-ctrip.com/images/0231m12000d6u36505CFA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230p12000d6toprk0444_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235z12000d6u0hkf84E0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-13', '花园双床房', '双床房', '家庭亲子', 57, 0, 19, 8, '["卫生状况","整体满意度","餐饮设施"]'::jsonb, '卫生状况', '整体满意度', '餐饮设施'),
('68027d10e3c98b0941765adc', '位置方便，房间虽然老旧，但面积很大，宽敞舒适，大厅恢宏气派，服务态度很好，窗外有瀑布景观，酒店有博物馆文化底蕴深厚', '["https://dimg04.c-ctrip.com/images/0235d12000drp5ry8E480_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000drp4xau020B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230x12000drp5pkv0AD4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-04-24', '花园双床房', '双床房', '商务出差', 57, 0, 2, 8, '["景观/朝向","周边配套","整体满意度"]'::jsonb, '景观/朝向', '周边配套', '整体满意度'),
('68027d10e3c98b0941765add', '考虑到要自由行动，所以选了交通便利的酒店，酒店边上就是地铁入口超级方便。过年期间酒店里也装饰的非常喜庆！', '["https://dimg04.c-ctrip.com/images/0236712000d91d0431DC4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231i12000d91dqm3861E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000d91djnmBE8C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-20', '城央绿意大床房', '大床房', '家庭亲子', 52, 0, 2, 6, '["交通便利性","整体满意度"]'::jsonb, '交通便利性', '整体满意度', NULL),
('68027d10e3c98b0941765ade', '房间干净，整洁，酒店的服务人员服务态度非常好。行政酒廊的工作人员服务周到，热情，Kanchan和Deepa笑容满面，相关酒店服务需求都会马上回应及解决，客房服务的小天也是服务周到，房间服务人员尽心尽力，还特意写了小卡片进行跟进，这个酒店要给个大大的赞??', '["https://dimg04.c-ctrip.com/images/0234g12000f5kasxlE4F5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000f5kgce758B6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000f5kk4kd096F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-17', '花园大床房', '大床房', '家庭亲子', 127, 0, 9, 9, '["客房服务","前台服务","卫生状况"]'::jsonb, '客房服务', '前台服务', '卫生状况'),
('68027d10e3c98b0941765adf', '不愧是老牌五星酒店的品牌，环境优美，房间也不错，服务态度非常好，有求必应，特别是酒店后花园的环境真的是太漂亮啦，下次来广州还会住花园酒店。', '["https://dimg04.c-ctrip.com/images/0203k12000cz9qumqC8D4_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0232812000cz9arcgBAC2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231h12000cz98pli70DC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232c12000cz98smiD338_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-19', '粤韵双床套房', '套房', '家庭亲子', 69, 0, 1, 7, '["整体满意度","前台服务","景观/朝向"]'::jsonb, '整体满意度', '前台服务', '景观/朝向'),
('68027d10e3c98b0941765ae0', '五星级酒店，三星的水准，入住体验最差的一次，壮观的门面，不如在入住的房间内多下工夫，金玉其外，败絮其中。', '["https://dimg04.c-ctrip.com/images/0236j12000d7pg0yoBD69_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000d7p4asqACC3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234412000d7p8o15D8F3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.7, 1, '2024-02-15', '城央绿意双床房', '双床房', '其他', 52, 6, 8, 7, '["整体满意度","房间设施"]'::jsonb, '整体满意度', '房间设施', NULL),
('68027d10e3c98b0941765ae1', '地理位置好，就在大街上容易看见。
房间重新装修了，喜欢这个格调，也喜欢大浴缸。
我住在701，我的小伙伴住在1949，他订的房间有行政酒廊，我们俩一起去了好几回，Cherry,Ken,Yuki,Carrie他们给了我们俩很好的服务。非常感恩。', '["https://dimg04.c-ctrip.com/images/0206p12000coekvutF903_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0236y12000coekh9kFA7E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000coec38v526C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-04', '花园大床房', '大床房', '商务出差', 121, 1, 3, 8, '[]'::jsonb, NULL, NULL, NULL),
('68027d10e3c98b0941765ae2', '花园酒店的历史悠久，大堂的圣诞气氛很浓厚，房间也还是蛮大的，有大圆桌和沙发，床上用品比较舒服，上30楼餐厅的电梯不太人性化，如果不是4部直达电梯的话就要往下坐到一楼再转；因为需要小朋友的拖鞋和浴衣，礼宾部的电话打了几次才有人接；因为在房间里面看到游泳池在布置婚礼，特意打电话问前台游泳池是不是关闭了，前台在没有确定的情况下就说没有关闭，就带着小孩穿着泳衣下去了，泳池的前台又说游泳池今天有活动不开放了，这么冷的天，又带小孩回房间了，行政酒廊的食物种类特别少，基本上是住过的五星酒店里最少的，欢乐时光的食品还没有希尔顿的下午茶种类丰富，估计是花园酒店不是国际连锁，不需要维护会员的忠诚度吧，但是味道还是不错的，行政酒廊的工作人员Carrie,Ken,Yuki也是特别的热情和专业。退房的时候开车出车库，显示要交144元停车费，可是刚刚才在礼宾部报备了车牌号啊，后面还有一堆车在等，比较狼狈。', '["https://dimg04.c-ctrip.com/images/0236512000co9ho9k42F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000co9jn4y8CDD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000co9h9qu2851_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-12-03', '花园大床房', '大床房', '家庭亲子', 394, 1, 2, 9, '["前台服务","公共设施","餐饮设施"]'::jsonb, '前台服务', '公共设施', '餐饮设施'),
('68027d10e3c98b0941765ae3', '房间和服务都不错。桃园馆中餐厅环境优雅。只是位于30楼的下午茶太差了，无论是出品还是格局都与酒店的档次极不相称，体验感太差，实在可惜了！', '["https://dimg04.c-ctrip.com/images/0232v12000czdax510AC2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000czdax5988D5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000czdb0dh8504_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236o12000czdb0djF5ED_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-20', '粤韵双床套房', '套房', '其他', 68, 0, 8, 8, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('68027d20e3c98b0941765ae4', '下午三点多办理入住的，人不多，等一两个就可以，不过办理过程稍微慢了一点点，花了十几分钟.小姐姐也一直在说不好意思，最后对房间还是满意的，应该是房间没清洁好临时给升了一个房型，然后比较安静没有受到附近施工??噪音的困扰.

 外观大堂都是老牌酒店的样子，内部重修装修过所以特别舒适大方.', '["https://dimg04.c-ctrip.com/images/0232y12000cou1lzm0BF5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y12000cou3irf3641_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230p12000cotxq9xE068_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-06', '红棉双床套房', '套房', '朋友出游', 142, 0, 1, 8, '["退房/入住效率","安静程度","整体满意度"]'::jsonb, '退房/入住效率', '安静程度', '整体满意度'),
('68027d20e3c98b0941765ae5', '岭南文化主题的酒店。
第二次在过年期间入住了，氛围感满满。春节期间酒店还有各种规定，大人小孩都玩得很开心…', '["https://dimg04.c-ctrip.com/images/0233g12000d6ejvr523FB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230x12000d6f82jwBB61_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-11', '花园大床房', '大床房', '家庭亲子', 53, 0, 2, 6, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027d20e3c98b0941765ae6', '酒店服务态度很好，周边交通很便利，出门就是地铁站，离点都德也很近，酒店春节期间各种活动，很喜庆，人气旺！', '["https://dimg04.c-ctrip.com/images/0233312000d6f95yu98D3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235v12000d6fobupC833_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233712000d6fp8k93EF2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-11', '城央绿意双床房', '双床房', '家庭亲子', 52, 0, 1, 7, '["交通便利性","周边配套","前台服务"]'::jsonb, '交通便利性', '周边配套', '前台服务'),
('68027d20e3c98b0941765ae7', '酒店设施服务很好', '["https://dimg04.c-ctrip.com/images/0230d12000e0yn2mpF22B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-16', '花园双床房', '双床房', '朋友出游', 8, 0, 25, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027d20e3c98b0941765ae8', '服务比以前好多了，二楼也很好吃。唯一缺点就是床太软了不适合有腰椎问题的老人家，希望酒店可以准备一些加硬的薄床垫。总体环境卫生服务用餐体验都很好。', '["https://dimg04.c-ctrip.com/images/0230712000cwjnft75B72_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230z12000cwjvisk1ADD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000cwjoozv6FF3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000cwk0wq7F815_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000cwjqbb1B7B4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-10', '城央绿意双床房', '双床房', '家庭亲子', 72, 0, 4, 8, '["房间设施","整体满意度","餐饮设施"]'::jsonb, '房间设施', '整体满意度', '餐饮设施'),
('68027d20e3c98b0941765ae9', '订了三间还升级了两间，价钱上是五星级里比较具有性价比的了，地理位置就在淘金，离地铁口也很近，去动物园两站路就可以了。', '["https://dimg04.c-ctrip.com/images/0235q12000dqzkisa978F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233e12000dqzlngc110F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233712000dqzlasb7D1A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-22', '花园大床房', '大床房', '家庭亲子', 58, 0, 40, 7, '["性价比","交通便利性","周边配套"]'::jsonb, '性价比', '交通便利性', '周边配套'),
('68027d20e3c98b0941765aea', '房间非常棒，cheek in的时间订的房间没有了，直接给我们升了房型。
酒店内的后花园和瀑布很漂亮。
还可以打电话到前台订专属导游，带着逛并介绍花园酒店。', '["https://dimg04.c-ctrip.com/images/0235s12000ddaa0t1547B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000dda79md5CB6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235x12000dd9l46s5609_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000dd9n4n3120C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233012000dd9mw7u1CDA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000dd9jhwy1778_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231o12000dd9n3td84DE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230y12000dd9hfj6F741_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230c12000dd9v2a73926_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-08', '红棉双床套房', '套房', '家庭亲子', 77, 0, 7, 7, '["前台服务","整体满意度","公共设施"]'::jsonb, '前台服务', '整体满意度', '公共设施'),
('68027d20e3c98b0941765aeb', '大促时购买了红棉大床房，其实本来想要双床房，结果订错了，check in时和前台小姐姐沟通一番，小姐姐不仅二话不说帮我换了双床房还帮我升房了，升成了说是新装修的粤韵。确实设施都比较新，但是美中不足的是特地带了浴球来泡澡，结果粤韵房间是没有浴缸的，有点小小遗憾~
体验了花园酒店的三个餐厅，瀑布餐厅，荔湾亭和锦鲤酒吧。瀑布餐厅可以看到花园酒店瀑布全景，阳光洒落在落地窗上，听着瀑布声吃早餐很惬意~就是早餐的种类并不多，可能是本身餐厅不是很大的缘故吧…
荔湾亭的菜色很普通，和在外面的粤菜店其实差不多，性价比并不高。而且在五星酒店里的都要收服务费的情况下，我们事先询问了可以挂酒店房间的账，而且之前的服务员也询问了房间号，结果一位中年女服务员在我们还没离开店的时候语气并不耐烦的大声问同伴，问我们的账结了没有，周遭都很安静的在吃饭，结果这样一弄搞得我们仿佛在吃霸王餐？而且这位服务员上菜也是带着不耐烦的上的，碗碟敲得砰砰响，不知道有什么不开心的事，这种服务态度还要收服务费的话确实并不值得吧。
锦鲤酒吧我们20点30以后到的还有乐队驻唱，座位也是沙发座可以坐在一起聊天，氛围很好，服务员推荐了特色鸡尾酒，蓉和一个宾治都很好喝~
酒店客房部的人员都很耐心有礼，花园酒店还有自己的博物馆，可以提前预约讲解，lisa小姐姐讲的很生动人也好美丽~为她打call~??', '["https://dimg04.c-ctrip.com/images/0231n12000cnnczux7974_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000cnnifky8163_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230x12000cnn4oliED8E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233712000cnni8d043B4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-30', '红棉大床套房', '套房', '朋友出游', 577, 0, 6, 9, '["前台服务","餐饮设施","客房服务"]'::jsonb, '前台服务', '餐饮设施', '客房服务'),
('68027d20e3c98b0941765aec', '酒店大堂装扮的非常喜庆，有舞龙舞狮表演，房间还有水果小吃赠送，服务员都非常热情，就是酒店实在太老旧了。', '["https://dimg04.c-ctrip.com/images/0236012000d6hme8xD28B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000d6i0jgz1D03_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000d6hyesv807F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000d6i1s9c8433_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-11', '花园双床房', '双床房', '家庭亲子', 51, 0, 6, 7, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68027d20e3c98b0941765aed', '今后四十年的历史发展，酒店经历过一次客房升级但时至今日过去些年日客房室内还是稍显老态，由于全地毯铺设的原因一开始进屋有些许霉味，空调开了一会会好一点。虽是老酒店但酒店的床垫非常舒适支撑性很好，柔软度也高这个一点非常棒。选择入住这家酒店不单单只是客房的体验，更是为了来见证感受这家富有传奇色彩的酒店，邓公的题字，建筑设计大师贝老参与的酒店设计将结构美学与实用性应用到了极致，Y型建筑设计 使空间得到了极大的使用同时兼顾了每个房间的采光和视野 是一个了不起的设计。这趟酒店之旅不需此行，值得体验。', '["https://dimg04.c-ctrip.com/images/0235d12000ckmqlpy8B1A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236012000ckmqehlC273_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m12000ckmrjgzF77D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000ckmvk1h2AB9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230512000ckmrmp6CCCF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000ckmuvsf3328_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000ckmru10A045_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000ckmvk1j017D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f12000ckmloy3CBC6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-11-14', '花园大床房', '大床房', '家庭亲子', 246, 0, 11, 9, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68027d2ae3c98b0941765aee', '一家酒店可以看到改革开放的发展史，贝律铭的设计初稿，邓小平的题字，***的奠基，***的进口设备申请。酒店38年的历程里记录了太多的历史瞬间。
      原本冲着酒店的人文氛围去的，果然一到就发现值得打卡的地方甚多，自带的博物馆和mini画展也可以去看看。沁春园的锦鲤仿佛通灵一般，能与人亲热互动。
      由于抵达当天已近半夜，前台办理入住很慢，提前电话预约的房间预留完全没有作用（酒店热线的接线人员一问三不知，提出的合理要求都很勉强记录），安排在5楼完全不是协议中写的18到21层。房间设备也比较老旧，体验感比较差。第2天再三要求下换到19楼，可惜订的双床房变大床房，孩子爸爸睡不下了。房间安排上的混乱与拖延，这一点真的是让人无语。
      总体来说，酒店服务人员都是礼貌热情的，虽然业务能力不强，但还是给人宾至如归的感觉。由于正值中秋节，酒店也很应景地给客人准备了一盒??。除却客房安排和房间老旧有所欠缺外，还是值得入住的。', '["https://dimg04.c-ctrip.com/images/0230u12000cbvjwj01B30_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000cbvgtwaD7C5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233312000cbvbnujE9A0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000cbvdy5e3BC2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236y12000cbvccceA3A1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235k12000cbveox748CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235x12000cbvfhd366B8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000cbvjy4oEC00_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235212000cbvd22vCD45_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-10-05', '花园双床房', '双床房', '家庭亲子', 420, 0, 19, 9, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('68027d2ae3c98b0941765aef', '住店很舒服，很喜欢接待我们的前台小姐姐，说话温柔，给我们很温暖的感觉。酒店的后花园也很棒，景色优美，如果能登小瀑布就更好了。', '["https://dimg04.c-ctrip.com/images/0230512000d36ri9d7966_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-31', '红棉大床套房', '套房', '家庭亲子', 62, 0, 10, 7, '["前台服务","景观/朝向","整体满意度"]'::jsonb, '前台服务', '景观/朝向', '整体满意度'),
('68027d2ae3c98b0941765af0', '酒店大堂富丽堂皇，后花园也非常漂亮，服务态度好，卫生干净，唯一不足就是房间稍微小了一点，总体感受还是不错，值得入住', '["https://dimg04.c-ctrip.com/images/0233812000d6vdxyq9609_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d12000d6v5fr34138_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m12000d6vf1dc4EF3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235a12000d6vft6e42CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000d6ve54sAE2F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-13', '花园双床房', '双床房', '家庭亲子', 57, 0, 14, 7, '["整体满意度","卫生状况","房间设施"]'::jsonb, '整体满意度', '卫生状况', '房间设施'),
('68027d2ae3c98b0941765af1', '作为携程的铂金会员升级了岭客汇的金卡，入住时升级了粤韵大床，因为才刚装修完没几年，环境自然是可以，且楼层服务员打扫房间很及时。但是花园大床房就不建议入住了，一进去房间就一股异味。早餐是在30楼用餐，品种较少，行政酒廊下午茶点心选择性也较少。游泳池是常温的，现在这个季节下水还是有点冷的。', '["https://dimg04.c-ctrip.com/images/0232512000cndbbpq628B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000cndb99kF74A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231c12000cnddi9k28CA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000cndbgzqCD8C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230712000cndl40d5F0C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-11-28', '花园大床房', '大床房', '家庭亲子', 143, 0, 8, 8, '["房间设施","餐饮设施","公共设施"]'::jsonb, '房间设施', '餐饮设施', '公共设施')
 ON CONFLICT (_id) DO NOTHING;
